function countFairPairs(nums, lower, upper) {
    let n = nums.length;
    let fair_pairs = 0;
    for (let i = 0; i < n; ++i) {
        for (let j = i + 1; j < n; ++j) {
            if ((lower <= nums[i] + nums[j]) && (nums[i] + nums[j] <= upper)) {
                fair_pairs++;
            }
        }
    }
    return fair_pairs;
}
